  1→import * as p from "@clack/prompts";
  2→import {
  3→	claudeCodeAdapter,
  4→	getAdapter,
  5→	getAvailableAdapters,
  6→	groupProjectsForCwd,
  7→	type ScannedProject,
  8→	type SessionFile,
  9→} from "@rudel/agent-adapters";
 10→import { buildCommand } from "@stricli/core";
 11→import pMap from "p-map";
 12→import { classifySession } from "../lib/classifier.js";
 13→import { loadCredentials } from "../lib/credentials.js";
 14→import {
 15→	loadFailedUploads,
 16→	recordFailedUpload,
 17→	removeFailedUpload,
 18→} from "../lib/failed-uploads.js";
 19→import { getGitInfo } from "../lib/git-info.js";
 20→import { getProjectOrgId } from "../lib/project-config.js";
 21→import { resolveSession } from "../lib/session-resolver.js";
 22→import {
 23→	DEFAULT_ENDPOINT,
 24→	SESSION_TAGS,
 25→	type SessionTag,
 26→} from "../lib/types.js";
 27→import { type UploadConfig, uploadSession } from "../lib/uploader.js";
 28→
 29→interface UploadFlags {
 30→	tag?: SessionTag;
 31→	endpoint: string;
 32→	classify: boolean;
 33→	dryRun: boolean;
 34→	org?: string;
 35→	retry: boolean;
 36→	concurrency: number;
 37→}
 38→
 39→async function runInteractiveUpload(flags: UploadFlags): Promise<void> {
 40→	const credentials = loadCredentials();
 41→	if (!credentials && !flags.dryRun) {
 42→		p.log.error("Not authenticated. Run `rudel login` first.");
 43→		process.exitCode = 1;
 44→		return;
 45→	}
 46→
 47→	p.intro("rudel upload");
 48→
 49→	const spin = p.spinner();
 50→	spin.start("Scanning projects...");
 51→
 52→	const adapters = getAvailableAdapters();
 53→	const allProjects: ScannedProject[] = [];
 54→	for (const adapter of adapters) {
 55→		const projects = await adapter.scanAllSessions();
 56→		allProjects.push(...projects);
 57→	}
 58→
 59→	spin.stop(`Found ${allProjects.length} project(s)`);
 60→
 61→	if (allProjects.length === 0) {
 62→		p.log.warn("No projects with sessions found.");
 63→		p.outro("Nothing to upload.");
 64→		return;
 65→	}
 66→
 67→	const cwd = process.cwd();
 68→	const grouped = groupProjectsForCwd(allProjects, cwd);
 69→
 70→	const options: Array<{
 71→		value: ScannedProject;
 72→		label: string;
 73→		hint: string;
 74→	}> = [];
 75→	const preSelected: ScannedProject[] = [];
 76→
 77→	for (const proj of grouped.current) {
 78→		options.push({
 79→			value: proj,
 80→			label: `[${getAdapterName(proj.source)}] ${proj.displayPath}`,
 81→			hint: sessionCountHint(proj.sessionCount),
 82→		});
 83→		preSelected.push(proj);
 84→	}
 85→
 86→	for (const sub of grouped.subfolders) {
 87→		const relative = sub.projectPath.slice(cwd.length + 1);
 88→		options.push({
 89→			value: sub,
 90→			label: `  [${getAdapterName(sub.source)}] ${relative}`,
 91→			hint: sessionCountHint(sub.sessionCount),
 92→		});
 93→		preSelected.push(sub);
 94→	}
 95→
 96→	for (const other of grouped.others) {
 97→		options.push({
 98→			value: other,
 99→			label: `[${getAdapterName(other.source)}] ${other.displayPath}`,
100→			hint: sessionCountHint(other.sessionCount),
101→		});
102→	}
103→
104→	const selected = await p.multiselect({
105→		message: "Select projects to upload",
106→		options,
107→		initialValues: preSelected,
108→		required: true,
109→	});
110→
111→	if (p.isCancel(selected)) {
112→		p.cancel("Upload cancelled.");
113→		return;
114→	}
115→
116→	const totalSessions = selected.reduce(
117→		(sum, proj) => sum + proj.sessionCount,
118→		0,
119→	);
120→	p.log.info(
121→		`Uploading ${totalSessions} session(s) from ${selected.length} project(s)`,
122→	);
123→
124→	const uploadConfig: UploadConfig = {
125→		endpoint: flags.endpoint,
126→		token: credentials?.token ?? "",
127→	};
128→
129→	// Flatten all sessions with their project context for concurrent upload
130→	const work: Array<{
131→		session: (typeof selected)[number]["sessions"][number];
132→		project: ScannedProject;
133→		adapter: ReturnType<typeof getAdapter>;
134→		gitInfo: Awaited<ReturnType<typeof getGitInfo>>;
135→		organizationId: string | undefined;
136→	}> = [];
137→
138→	for (const project of selected) {
139→		const adapter = getAdapter(project.source);
140→		const gitInfo = await getGitInfo(project.projectPath);
141→		const organizationId =
142→			flags.org ?? (await getProjectOrgId(project.projectPath));
143→		for (const session of project.sessions) {
144→			work.push({ session, project, adapter, gitInfo, organizationId });
145→		}
146→	}
147→
148→	const uploadSpin = p.spinner();
149→	uploadSpin.start("Uploading sessions...");
150→
151→	let succeeded = 0;
152→	let failed = 0;
153→	let completed = 0;
154→	const errors: Array<{ sessionId: string; project: string; error: string }> =
155→		[];
156→
157→	await pMap(
158→		work,
159→		async ({ session, project, adapter, gitInfo, organizationId }) => {
160→			try {
161→				const request = await adapter.buildUploadRequest(session, {
162→					tag: flags.tag,
163→					gitInfo,
164→					organizationId,
165→				});
166→
167→				if (!flags.tag && flags.classify) {
168→					const classified = await classifySession(request.content);
169→					if (classified) {
170→						(request as { tag?: string }).tag = classified;
171→					}
172→				}
173→
174→				if (flags.dryRun) {
175→					succeeded++;
176→					completed++;
177→					uploadSpin.message(`[${completed}/${totalSessions}] Uploading...`);
178→					return;
179→				}
180→
181→				const result = await uploadSession(request, {
182→					...uploadConfig,
183→					onRetry: (attempt, maxAttempts, error) => {
184→						uploadSpin.message(
185→							`[${completed + 1}/${totalSessions}] Retrying (${attempt}/${maxAttempts}) after ${error}`,
186→						);
187→					},
188→				});
189→				if (result.success) {
190→					succeeded++;
191→					await removeFailedUpload(session.sessionId);
192→				} else {
193→					failed++;
194→					const error = result.error ?? "Unknown error";
195→					errors.push({
196→						sessionId: session.sessionId,
197→						project: project.displayPath,
198→						error,
199→					});
200→					await recordFailedUpload({
201→						sessionId: session.sessionId,
202→						transcriptPath: session.transcriptPath,
203→						projectPath: session.projectPath,
204→						source: project.source,
205→						organizationId,
206→						error,
207→					});
208→				}
209→			} catch (error) {
210→				failed++;
211→				const errorMessage =
212→					error instanceof Error ? error.message : String(error);
213→				errors.push({
214→					sessionId: session.sessionId,
215→					project: project.displayPath,
216→					error: errorMessage,
217→				});
218→				await recordFailedUpload({
219→					sessionId: session.sessionId,
220→					transcriptPath: session.transcriptPath,
221→					projectPath: session.projectPath,
222→					source: project.source,
223→					organizationId,
224→					error: errorMessage,
225→				});
226→			} finally {
227→				completed++;
228→				uploadSpin.message(`[${completed}/${totalSessions}] Uploading...`);
229→			}
230→		},
231→		{ concurrency: flags.concurrency, stopOnError: false },
232→	);
233→
234→	uploadSpin.stop("Upload complete");
235→
236→	if (succeeded > 0) {
237→		p.log.success(`${succeeded} session(s) uploaded successfully`);
238→	}
239→	if (failed > 0) {
240→		p.log.error(`${failed} session(s) failed`);
241→		for (const err of errors.slice(0, 5)) {
242→			p.log.warn(`  ${err.project}/${err.sessionId}: ${err.error}`);
243→		}
244→		if (errors.length > 5) {
245→			p.log.warn(`  ...and ${errors.length - 5} more`);
246→		}
247→		p.log.info("Run `rudel upload --retry` to retry failed uploads.");
248→	}
249→
250→	if (flags.dryRun) {
251→		p.outro("Dry run complete — no sessions were uploaded.");
252→	} else {
253→		p.outro("Done!");
254→	}
255→
256→	if (failed > 0) {
257→		process.exitCode = 1;
258→	}
259→}
260→
261→function getAdapterName(source: string): string {
262→	try {
263→		return getAdapter(source).name;
264→	} catch {
265→		return source;
266→	}
267→}
268→
269→function sessionCountHint(count: number): string {
270→	return `${count} session${count !== 1 ? "s" : ""}`;
271→}
272→
273→async function runSingleUpload(
274→	flags: UploadFlags,
275→	session: string,
276→): Promise<void> {
277→	const write = (msg: string) => {
278→		process.stdout.write(`${msg}\n`);
279→	};
280→	const writeError = (msg: string) => {
281→		process.stderr.write(`${msg}\n`);
282→	};
283→
284→	const credentials = loadCredentials();
285→	if (!credentials && !flags.dryRun) {
286→		writeError("Error: Not authenticated. Run `rudel login` first.");
287→		process.exitCode = 1;
288→		return;
289→	}
290→
291→	write(`Resolving session: ${session}`);
292→	let sessionInfo: Awaited<ReturnType<typeof resolveSession>>;
293→	try {
294→		sessionInfo = await resolveSession(session);
295→	} catch (error) {
296→		writeError(
297→			`Error: ${error instanceof Error ? error.message : String(error)}`,
298→		);
299→		process.exitCode = 1;
300→		return;
301→	}
302→	write(`Found session at: ${sessionInfo.transcriptPath}`);
303→
304→	const gitInfo = await getGitInfo(sessionInfo.projectPath);
305→	if (gitInfo.repository) write(`Repository: ${gitInfo.repository}`);
306→	if (gitInfo.branch) write(`Branch: ${gitInfo.branch}`);
307→
308→	const organizationId =
309→		flags.org ?? (await getProjectOrgId(sessionInfo.projectPath));
310→	if (organizationId) write(`Organization: ${organizationId}`);
311→
312→	write("Building upload request...");
313→	const sessionFile: SessionFile = {
314→		sessionId: sessionInfo.sessionId,
315→		transcriptPath: sessionInfo.transcriptPath,
316→		projectPath: sessionInfo.projectPath,
317→	};
318→
319→	const request = await claudeCodeAdapter.buildUploadRequest(sessionFile, {
320→		tag: flags.tag,
321→		gitInfo,
322→		organizationId,
323→	});
324→
325→	write(`Transcript: ${request.content.length} bytes`);
326→	if (request.subagents && request.subagents.length > 0) {
327→		write(`Subagents: ${request.subagents.length} file(s)`);
328→	}
329→
330→	if (!flags.tag && flags.classify) {
331→		write("Classifying session...");
332→		const classified = await classifySession(request.content);
333→		if (classified) {
334→			(request as { tag?: string }).tag = classified;
335→			write(`Classified as: ${classified}`);
336→		}
337→	}
338→
339→	if (flags.dryRun) {
340→		const preview = {
341→			...request,
342→			content: `[${request.content.length} bytes]`,
343→			subagents: request.subagents?.map((s) => ({
344→				...s,
345→				content: `[${s.content.length} bytes]`,
346→			})),
347→		};
348→		write("Dry run - would upload:");
349→		write(JSON.stringify(preview, null, 2));
350→		return;
351→	}
352→
353→	write("Uploading...");
354→	const result = await uploadSession(request, {
355→		endpoint: flags.endpoint,
356→		// biome-ignore lint/style/noNonNullAssertion: validated above with early return
357→		token: credentials!.token,
358→	});
359→
360→	if (result.success) {
361→		write("Upload successful!");
362→	} else {
363→		writeError(`Upload failed: ${result.error}`);
364→		process.exitCode = 1;
365→	}
366→}
367→
368→async function runRetryUpload(flags: UploadFlags): Promise<void> {
369→	const credentials = loadCredentials();
370→	if (!credentials) {
371→		p.log.error("Not authenticated. Run `rudel login` first.");
372→		process.exitCode = 1;
373→		return;
374→	}
375→
376→	p.intro("rudel upload --retry");
377→
378→	const failures = await loadFailedUploads();
379→	if (failures.length === 0) {
380→		p.outro("No failed uploads to retry.");
381→		return;
382→	}
383→
384→	p.log.info(`Found ${failures.length} failed upload(s):`);
385→	for (const f of failures.slice(0, 10)) {
386→		p.log.warn(`  ${f.sessionId}: ${f.error} (${f.failedAt})`);
387→	}
388→	if (failures.length > 10) {
389→		p.log.warn(`  ...and ${failures.length - 10} more`);
390→	}
391→
392→	const shouldRetry = await p.confirm({
393→		message: `Retry all ${failures.length} failed upload(s)?`,
394→		initialValue: true,
395→	});
396→
397→	if (p.isCancel(shouldRetry) || !shouldRetry) {
398→		p.cancel("Retry cancelled.");
399→		return;
400→	}
401→
402→	const endpoint = flags.endpoint;
403→	let succeeded = 0;
404→	let failed = 0;
405→	let completed = 0;
406→
407→	const retrySpin = p.spinner();
408→	retrySpin.start("Retrying uploads...");
409→
410→	await pMap(
411→		failures,
412→		async (failure) => {
413→			try {
414→				const adapter = failure.source
415→					? getAdapter(failure.source)
416→					: claudeCodeAdapter;
417→				const sessionFile: SessionFile = {
418→					sessionId: failure.sessionId,
419→					transcriptPath: failure.transcriptPath,
420→					projectPath: failure.projectPath,
421→				};
422→				const gitInfo = await getGitInfo(failure.projectPath);
423→				const organizationId =
424→					flags.org ??
425→					failure.organizationId ??
426→					(await getProjectOrgId(failure.projectPath));
427→
428→				const request = await adapter.buildUploadRequest(sessionFile, {
429→					tag: flags.tag,
430→					gitInfo,
431→					organizationId,
432→				});
433→
434→				const result = await uploadSession(request, {
435→					endpoint,
436→					token: credentials.token,
437→					onRetry: (attempt, maxAttempts, error) => {
438→						retrySpin.message(
439→							`[${completed + 1}/${failures.length}] Retrying (${attempt}/${maxAttempts}) after ${error}...`,
440→						);
441→					},
442→				});
443→
444→				if (result.success) {
445→					succeeded++;
446→					await removeFailedUpload(failure.sessionId);
447→				} else {
448→					failed++;
449→					await recordFailedUpload({
450→						...failure,
451→						error: result.error ?? "Unknown error",
452→					});
453→				}
454→			} catch (error) {
455→				failed++;
456→				const errorMessage =
457→					error instanceof Error ? error.message : String(error);
458→				await recordFailedUpload({ ...failure, error: errorMessage });
459→			} finally {
460→				completed++;
461→				retrySpin.message(
462→					`[${completed}/${failures.length}] Retrying uploads...`,
463→				);
464→			}
465→		},
466→		{ concurrency: flags.concurrency, stopOnError: false },
467→	);
468→
469→	retrySpin.stop("Retry complete");
470→
471→	if (succeeded > 0) {
472→		p.log.success(`${succeeded} session(s) uploaded`);
473→	}
474→	if (failed > 0) {
475→		p.log.error(`${failed} session(s) still failing`);
476→	}
477→
478→	p.outro("Done!");
479→
480→	if (failed > 0) {
481→		process.exitCode = 1;
482→	}
483→}
484→
485→async function runUpload(
486→	flags: UploadFlags,
487→	...sessions: string[]
488→): Promise<void> {
489→	if (flags.retry) {
490→		return runRetryUpload(flags);
491→	}
492→	if (sessions.length === 0) {
493→		return runInteractiveUpload(flags);
494→	}
495→	return runSingleUpload(flags, sessions[0] as string);
496→}
497→
498→export const uploadCommand = buildCommand({
499→	loader: async () => ({ default: runUpload }),
500→	parameters: {
501→		positional: {
502→			kind: "array",
503→			parameter: {
504→				brief: "Session ID or path to a session .jsonl file",
505→				parse: String,
506→				placeholder: "session",
507→			},
508→		},
509→		flags: {
510→			tag: {
511→				kind: "enum",
512→				values: [...SESSION_TAGS],
513→				brief: "Session tag/category",
514→				optional: true,
515→			},
516→			endpoint: {
517→				kind: "parsed",
518→				parse: String,
519→				brief: "Override the upload endpoint URL",
520→				default: DEFAULT_ENDPOINT,
521→			},
522→			classify: {
523→				kind: "boolean",
524→				brief: "Auto-classify session tag using Claude CLI",
525→				default: false,
526→			},
527→			dryRun: {
528→				kind: "boolean",
529→				brief: "Preview what would be uploaded without sending",
530→				default: false,
531→			},
532→			org: {
533→				kind: "parsed",
534→				parse: String,
535→				brief: "Override the organization ID to upload to",
536→				optional: true,
537→			},
538→			retry: {
539→				kind: "boolean",
540→				brief: "Retry previously failed uploads",
541→				default: false,
542→			},
543→			concurrency: {
544→				kind: "parsed",
545→				parse: Number,
546→				brief: "Max concurrent uploads",
547→				default: "5",
548→			},
549→		},
550→		aliases: {
551→			t: "tag",
552→			c: "classify",
553→			n: "dryRun",
554→			o: "org",
555→			r: "retry",
556→			j: "concurrency",
557→		},
558→	},
