104→	const selected = await p.multiselect({
105→		message: "Select projects to upload",
106→		options,
107→		initialValues: preSelected,
108→		required: true,
109→	});
110→
111→	if (p.isCancel(selected)) {
112→		p.cancel("Upload cancelled.");
113→		return;
114→	}
115→
116→	const totalSessions = selected.reduce(
117→		(sum, proj) => sum + proj.sessionCount,
118→		0,
119→	);
120→	p.log.info(
121→		`Uploading ${totalSessions} session(s) from ${selected.length} project(s)`,
122→	);
123→
124→	const uploadConfig: UploadConfig = {
125→		endpoint: flags.endpoint,
126→		token: credentials?.token ?? "",
127→	};
128→
129→	// Flatten all sessions with their project context for concurrent upload
130→	const work: Array<{
131→		session: (typeof selected)[number]["sessions"][number];
132→		project: ScannedProject;
133→		adapter: ReturnType<typeof getAdapter>;
134→		gitInfo: Awaited<ReturnType<typeof getGitInfo>>;
135→		organizationId: string | undefined;
136→	}> = [];
137→
138→	for (const project of selected) {
139→		const adapter = getAdapter(project.source);
140→		const gitInfo = await getGitInfo(project.projectPath);
141→		const organizationId =
142→			flags.org ?? (await getProjectOrgId(project.projectPath));
143→		for (const session of project.sessions) {
144→			work.push({ session, project, adapter, gitInfo, organizationId });
145→		}
146→	}
147→
148→	const uploadSpin = p.spinner();
149→	uploadSpin.start("Uploading sessions...");
150→
151→	let succeeded = 0;
152→	let failed = 0;
153→	let completed = 0;
154→	const errors: Array<{ sessionId: string; project: string; error: string }> =
155→		[];
156→
157→	await pMap(
158→		work,
159→		async ({ session, project, adapter, gitInfo, organizationId }) => {
160→			try {
161→				const request = await adapter.buildUploadRequest(session, {
162→					tag: flags.tag,
163→					gitInfo,
164→					organizationId,
165→				});
166→
167→				if (!flags.tag && flags.classify) {
168→					const classified = await classifySession(request.content);
169→					if (classified) {
170→						(request as { tag?: string }).tag = classified;
171→					}
172→				}
173→
174→				if (flags.dryRun) {
175→					succeeded++;
176→					completed++;
177→					uploadSpin.message(`[${completed}/${totalSessions}] Uploading...`);
178→					return;
179→				}
180→
181→				const result = await uploadSession(request, {
182→					...uploadConfig,
183→					onRetry: (attempt, maxAttempts, error) => {
184→						uploadSpin.message(
185→							`[${completed + 1}/${totalSessions}] Retrying (${attempt}/${maxAttempts}) after ${error}`,
186→						);
187→					},
188→				});
189→				if (result.success) {
190→					succeeded++;
191→					await removeFailedUpload(session.sessionId);
192→				} else {
193→					failed++;
194→					const error = result.error ?? "Unknown error";
195→					errors.push({
196→						sessionId: session.sessionId,
197→						project: project.displayPath,
198→						error,
199→					});
200→					await recordFailedUpload({
201→						sessionId: session.sessionId,
202→						transcriptPath: session.transcriptPath,
203→						projectPath: session.projectPath,
204→						source: project.source,
205→						organizationId,
206→						error,
207→					});
208→				}
209→			} catch (error) {
210→				failed++;
211→				const errorMessage =
212→					error instanceof Error ? error.message : String(error);
213→				errors.push({
214→					sessionId: session.sessionId,
215→					project: project.displayPath,
216→					error: errorMessage,
217→				});
218→				await recordFailedUpload({
219→					sessionId: session.sessionId,
220→					transcriptPath: session.transcriptPath,
221→					projectPath: session.projectPath,
222→					source: project.source,
223→					organizationId,
224→					error: errorMessage,
225→				});
226→			} finally {
227→				completed++;
228→				uploadSpin.message(`[${completed}/${totalSessions}] Uploading...`);
229→			}
230→		},
231→		{ concurrency: flags.concurrency, stopOnError: false },
232→	);
233→
234→	uploadSpin.stop("Upload complete");
235→
236→	if (succeeded > 0) {
237→		p.log.success(`${succeeded} session(s) uploaded successfully`);
238→	}
239→	if (failed > 0) {
240→		p.log.error(`${failed} session(s) failed`);
241→		for (const err of errors.slice(0, 5)) {
242→			p.log.warn(`  ${err.project}/${err.sessionId}: ${err.error}`);
243→		}
244→		if (errors.length > 5) {
245→			p.log.warn(`  ...and ${errors.length - 5} more`);
246→		}
247→		p.log.info("Run `rudel upload --retry` to retry failed uploads.");
248→	}
249→
250→	if (flags.dryRun) {
251→		p.outro("Dry run complete — no sessions were uploaded.");
252→	} else {
