368→async function runRetryUpload(flags: UploadFlags): Promise<void> {
369→	const credentials = loadCredentials();
370→	if (!credentials) {
371→		p.log.error("Not authenticated. Run `rudel login` first.");
372→		process.exitCode = 1;
373→		return;
374→	}
375→
376→	p.intro("rudel upload --retry");
377→
378→	const failures = await loadFailedUploads();
379→	if (failures.length === 0) {
380→		p.outro("No failed uploads to retry.");
381→		return;
382→	}
383→
384→	p.log.info(`Found ${failures.length} failed upload(s):`);
385→	for (const f of failures.slice(0, 10)) {
386→		p.log.warn(`  ${f.sessionId}: ${f.error} (${f.failedAt})`);
387→	}
388→	if (failures.length > 10) {
389→		p.log.warn(`  ...and ${failures.length - 10} more`);
390→	}
391→
392→	const shouldRetry = await p.confirm({
393→		message: `Retry all ${failures.length} failed upload(s)?`,
394→		initialValue: true,
395→	});
396→
397→	if (p.isCancel(shouldRetry) || !shouldRetry) {
398→		p.cancel("Retry cancelled.");
399→		return;
400→	}
401→
402→	const endpoint = flags.endpoint;
403→	let succeeded = 0;
404→	let failed = 0;
405→	let completed = 0;
406→
407→	const retrySpin = p.spinner();
408→	retrySpin.start("Retrying uploads...");
409→
410→	await pMap(
411→		failures,
412→		async (failure) => {
413→			try {
414→				const adapter = failure.source
415→					? getAdapter(failure.source)
416→					: claudeCodeAdapter;
417→				const sessionFile: SessionFile = {
418→					sessionId: failure.sessionId,
419→					transcriptPath: failure.transcriptPath,
420→					projectPath: failure.projectPath,
421→				};
422→				const gitInfo = await getGitInfo(failure.projectPath);
423→				const organizationId =
424→					flags.org ??
425→					failure.organizationId ??
426→					(await getProjectOrgId(failure.projectPath));
427→
428→				const request = await adapter.buildUploadRequest(sessionFile, {
429→					tag: flags.tag,
430→					gitInfo,
431→					organizationId,
432→				});
433→
434→				const result = await uploadSession(request, {
435→					endpoint,
436→					token: credentials.token,
437→					onRetry: (attempt, maxAttempts, error) => {
438→						retrySpin.message(
439→							`[${completed + 1}/${failures.length}] Retrying (${attempt}/${maxAttempts}) after ${error}...`,
440→						);
441→					},
442→				});
443→
444→				if (result.success) {
445→					succeeded++;
446→					await removeFailedUpload(failure.sessionId);
447→				} else {
448→					failed++;
449→					await recordFailedUpload({
450→						...failure,
451→						error: result.error ?? "Unknown error",
452→					});
453→				}
454→			} catch (error) {
455→				failed++;
456→				const errorMessage =
457→					error instanceof Error ? error.message : String(error);
458→				await recordFailedUpload({ ...failure, error: errorMessage });
459→			} finally {
460→				completed++;
461→				retrySpin.message(
462→					`[${completed}/${failures.length}] Retrying uploads...`,
463→				);
464→			}
465→		},
466→		{ concurrency: flags.concurrency, stopOnError: false },
467→	);
468→
469→	retrySpin.stop("Retry complete");
470→
471→	if (succeeded > 0) {
472→		p.log.success(`${succeeded} session(s) uploaded`);
473→	}
474→	if (failed > 0) {
475→		p.log.error(`${failed} session(s) still failing`);
476→	}
477→
478→	p.outro("Done!");
479→
480→	if (failed > 0) {
481→		process.exitCode = 1;
482→	}
483→}
484→
485→async function runUpload(
486→	flags: UploadFlags,
487→	...sessions: string[]
488→): Promise<void> {
489→	if (flags.retry) {
490→		return runRetryUpload(flags);
491→	}
492→	if (sessions.length === 0) {
493→		return runInteractiveUpload(flags);
494→	}
495→	return runSingleUpload(flags, sessions[0] as string);
496→}
497→
498→export const uploadCommand = buildCommand({
499→	loader: async () => ({ default: runUpload }),
500→	parameters: {
501→		positional: {
502→			kind: "array",
503→			parameter: {
504→				brief: "Session ID or path to a session .jsonl file",
505→				parse: String,
506→				placeholder: "session",
507→			},
508→		},
509→		flags: {
510→			tag: {
511→				kind: "enum",
512→				values: [...SESSION_TAGS],
513→				brief: "Session tag/category",
514→				optional: true,
515→			},
516→			endpoint: {
517→				kind: "parsed",
518→				parse: String,
519→				brief: "Override the upload endpoint URL",
520→				default: DEFAULT_ENDPOINT,
521→			},
522→			classify: {
523→				kind: "boolean",
524→				brief: "Auto-classify session tag using Claude CLI",
525→				default: false,
526→			},
527→			dryRun: {
528→				kind: "boolean",
529→				brief: "Preview what would be uploaded without sending",
530→				default: false,
531→			},
532→			org: {
533→				kind: "parsed",
534→				parse: String,
535→				brief: "Override the organization ID to upload to",
536→				optional: true,
537→			},
538→			retry: {
539→				kind: "boolean",
540→				brief: "Retry previously failed uploads",
541→				default: false,
542→			},
543→			concurrency: {
544→				kind: "parsed",
545→				parse: Number,
546→				brief: "Max concurrent uploads",
547→				default: "5",
548→			},
549→		},
550→		aliases: {
551→			t: "tag",
552→			c: "classify",
553→			n: "dryRun",
554→			o: "org",
555→			r: "retry",
556→			j: "concurrency",
557→		},
558→	},
559→	docs: {
560→		brief:
561→			"Upload session transcripts (Claude Code & Codex). No args = interactive project picker.",
562→	},
563→});
