317→	p.intro("rudel upload --retry");
318→
319→	const failures = await loadFailedUploads();
320→	if (failures.length === 0) {
321→		p.outro("No failed uploads to retry.");
322→		return;
323→	}
324→
325→	p.log.info(`Found ${failures.length} failed upload(s):`);
326→	for (const f of failures.slice(0, 10)) {
327→		p.log.warn(`  ${f.sessionId}: ${f.error} (${f.failedAt})`);
328→	}
329→	if (failures.length > 10) {
330→		p.log.warn(`  ...and ${failures.length - 10} more`);
331→	}
332→
333→	const shouldRetry = await p.confirm({
334→		message: `Retry all ${failures.length} failed upload(s)?`,
335→		initialValue: true,
336→	});
337→
338→	if (p.isCancel(shouldRetry) || !shouldRetry) {
339→		p.cancel("Retry cancelled.");
340→		return;
341→	}
342→
343→	const endpoint = flags.endpoint;
344→
345→	type RetryItem = BatchUploadItem & {
346→		failure: (typeof failures)[number];
347→	};
348→
349→	const items: RetryItem[] = failures.map((f) => ({
350→		sessionId: f.sessionId,
351→		label: f.sessionId,
352→		transcriptPath: f.transcriptPath,
353→		projectPath: f.projectPath,
354→		source: f.source,
355→		organizationId: f.organizationId,
356→		failure: f,
357→	}));
358→
359→	const summary = await runBatchUpload({
360→		items,
361→		label: "Retrying uploads...",
362→		concurrency: flags.concurrency,
363→		upload: async (item, onRetry) => {
364→			const adapter = item.failure.source
365→				? getAdapter(item.failure.source)
366→				: claudeCodeAdapter;
367→			const sessionFile: SessionFile = {
368→				sessionId: item.failure.sessionId,
369→				transcriptPath: item.failure.transcriptPath,
370→				projectPath: item.failure.projectPath,
371→			};
372→			const gitInfo = await getGitInfo(item.failure.projectPath);
373→			const organizationId =
374→				flags.org ??
375→				item.failure.organizationId ??
376→				(await getProjectOrgId(item.failure.projectPath));
377→
378→			const request = await adapter.buildUploadRequest(sessionFile, {
379→				tag: flags.tag,
380→				gitInfo,
381→				organizationId,
382→			});
383→
384→			return uploadSession(request, {
385→				endpoint,
386→				token: credentials.token,
387→				onRetry,
388→			});
389→		},
390→	});
391→
392→	renderBatchSummary(summary);
393→
394→	p.outro("Done!");
395→
396→	if (summary.failed > 0) {
397→		process.exitCode = 1;
398→	}
399→}
400→
401→async function runUpload(
402→	flags: UploadFlags,
403→	...sessions: string[]
404→): Promise<void> {
405→	if (flags.retry) {
406→		return runRetryUpload(flags);
407→	}
408→	if (sessions.length === 0) {
409→		return runInteractiveUpload(flags);
410→	}
411→	return runSingleUpload(flags, sessions[0] as string);
412→}
413→
414→export const uploadCommand = buildCommand({
415→	loader: async () => ({ default: runUpload }),
416→	parameters: {
417→		positional: {
418→			kind: "array",
419→			parameter: {
420→				brief: "Session ID or path to a session .jsonl file",
421→				parse: String,
422→				placeholder: "session",
423→			},
424→		},
425→		flags: {
426→			tag: {
427→				kind: "enum",
428→				values: [...SESSION_TAGS],
429→				brief: "Session tag/category",
430→				optional: true,
431→			},
432→			endpoint: {
433→				kind: "parsed",
434→				parse: String,
435→				brief: "Override the upload endpoint URL",
436→				default: DEFAULT_ENDPOINT,
437→			},
438→			classify: {
439→				kind: "boolean",
440→				brief: "Auto-classify session tag using Claude CLI",
441→				default: false,
442→			},
443→			dryRun: {
444→				kind: "boolean",
445→				brief: "Preview what would be uploaded without sending",
446→				default: false,
447→			},
448→			org: {
449→				kind: "parsed",
450→				parse: String,
451→				brief: "Override the organization ID to upload to",
452→				optional: true,
453→			},
454→			retry: {
455→				kind: "boolean",
456→				brief: "Retry previously failed uploads",
457→				default: false,
458→			},
459→			concurrency: {
460→				kind: "parsed",
461→				parse: Number,
462→				brief: "Max concurrent uploads",
463→				default: "5",
464→			},
465→		},
